import {NUMBER_FORMAT_STYLE, SUPPORT_CURRENCY, SUPPORT_LOCALES} from "./enum";

/**
 * TODO 后面统一替换所有数字类的 formatter
  */
export const currencyFormatter = Intl.NumberFormat(SUPPORT_LOCALES.EN_US, { style: NUMBER_FORMAT_STYLE.CURRENCY, currency: SUPPORT_CURRENCY.USD });

export const decimalFormatter = Intl.NumberFormat(SUPPORT_LOCALES.EN_US, { style: NUMBER_FORMAT_STYLE.DECIMAL})

export const percentFormatter = Intl.NumberFormat(SUPPORT_LOCALES.EN_US, { style: NUMBER_FORMAT_STYLE.PERCENT} )